let input= parameters.input
let type= parameters.type
function validateInput(input, type) {
  switch (type) {
      case 'type_string':
      return typeof input === 'string';

    case 'type_int':
      return /\d+$/.test(input.trim());

    case 'type_boolean':
      input = input.toLowerCase();
      return input === 'true' || input === 'false';

    case 'type_float':
      return !isNaN(input) && /\d+\.\d+$/.test(input); 

    case 'type_string_array':
      try {
        let arr = JSON.parse(input);
        return Array.isArray(arr) && arr.every(item => typeof item === 'string');
      } catch (e) {
        return false; 
      }
      break;

    case 'type_int_array':
      try {
        let arr = JSON.parse(input);
        if (!Array.isArray(arr)) return false;   
        return arr.every(item => typeof item === 'number');
      } catch (e) {
        return false; 
      }
      break;

    case 'type_boolean_array':
      try {
        let arr = JSON.parse(input);
        return Array.isArray(arr) && arr.every(item => typeof item === 'boolean');
      } catch (e) {
        return false; 
      }
      break;

    case 'type_float_array':
      try {
        let arr = JSON.parse(input);
        if (!Array.isArray(arr)) return false;
        return arr.every(item => typeof item === 'number' && (item % 1 !== 0 || input.includes(item.toFixed(1))));
      } catch (e) {
        return false;
      }
      break;

    case 'type_json':
      try {
        JSON.parse(input);
        return true; 
      } catch (e) {
        return false; 
      }
      break;

    default:
      return false; 
  }
}

if(!validateInput(input, type)) {
  invalidInputErrorMessage.setValue("Invalid input for " + type);
} else {
  invalidInputErrorMessage.setValue("");
  const maxSize = 10000;

  if (type.endsWith('_array')) {
    try {
      const arr = JSON.parse(input);
      for (let i = 0; i < arr.length; i++) {
        const itemSize = new TextEncoder().encode(arr[i]).length;
        if (itemSize > maxSize && !isAdmin.value) {
          invalidInputErrorMessage.setValue(
            `Config value size exceeded for item at index ${i}, maxSize: ${maxSize} bytes, valueSize: ${itemSize} bytes, reach out to #cp-onboarding`
          );
          break;
        }
      }
    } catch (e) {
      invalidInputErrorMessage.setValue(
            `Error in parsing config value`
          );
    }
  } else {
    // Check if the size of the input exceeds 10,000 bytes for non-array types
    const inputSize = new TextEncoder().encode(input).length;
    if (inputSize > maxSize && !isAdmin.value) {
      invalidInputErrorMessage.setValue(
        `Config value size exceeded, maxSize: ${maxSize} bytes, valueSize: ${inputSize} bytes, reach out to #cp-onboarding`
      );
    } 
  }
}
